import{_ as n,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"98. Industry Ohs Working Group","description":"","frontmatter":{"title":"98. Industry Ohs Working Group","eba":"Nurses and Midwives 2024-2028","topics":["ohs","workers-comp"]},"headers":[],"relativePath":"ebas/nurses-midwives/ohs/98-industry-ohs-working-group.md","filePath":"ebas/nurses-midwives/ohs/98-industry-ohs-working-group.md"}'),i={name:"ebas/nurses-midwives/ohs/98-industry-ohs-working-group.md"};function s(a,e,p,d,c,l){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_98-industry-ohs-working-group" tabindex="-1">98. Industry Ohs Working Group <a class="header-anchor" href="#_98-industry-ohs-working-group" aria-label="Permalink to &quot;98. Industry Ohs Working Group&quot;">​</a></h1><p><strong>98.1</strong> The Employers (and their representative), the Employees and the Unions will proactively cooperate in the development and recommendation of measures to improve occupational health and safety outcomes, with the intent of improving Employee health and safety, preventing injury, illness and incapacity (and hence workers compensation payments) and supporting effective and responsive return to work, with a particular focus on the following:</p><p><strong>(a)</strong> psychological injuries;</p><p><strong>(b)</strong> safe patient and manual handling processes;</p><p><strong>(c)</strong> safe rostering practices and prevention of fatigue risks;</p><p><strong>(d)</strong> occupational violence and aggression prevention programs;</p><p><strong>(e)</strong> education for NUMs/ANUMs regarding management of Employees; and</p><p><strong>(f)</strong> workplace bullying.</p><p><strong>98.2</strong> The proactive cooperation described at clause 98.1 with respect to the priorities identified above, will seek to achieve the following:</p><p><strong>(a)</strong> In the case of psychological injuries, a shared approach to:</p><p><strong>(i)</strong> addressing work related causes of psychological injury, including bullying, sexual harassment and burn out; and</p><p><strong>(ii)</strong> finding available positions for an Employee with a psychological injury, including but not limited to positions with an alternate Employer by agreement where the Employee’s treating practitioner determines that it is unlikely that the Employee could return to work with their Employer but could return to work with an alternate Employer. In the first instance, the primary focus will be with respect to work-related psychological injuries;</p><p><strong>(a)</strong> in the case of safe patient and manual handling processes, reduction of musculoskeletal injuries by identifying requirements for safe patient and manual handling programs including recommendation of principles and practices to prevent and reduce the associated risks;</p><p><strong>(b)</strong> in the case of safe rostering practices, identification of staff and patient safety risks associated with working hours, shift work, rostering practices and fatigue, including any preventable hazards, and recommendation of principles and practices to prevent and reduce the associated risks;</p><p><strong>(c)</strong> in the case of occupational violence and aggression prevention programs, ensuring the prevention and/or appropriate management of occupational violence to reduce associated injuries and illness, including the long-term mental health implications of exposure to continuing violence and aggression, including recommendation of principles and practices to prevent and reduce the associated risks, consistent with the ANMF 10 Point Plan, and making recommendations to address these;</p><p><strong>(d)</strong> in the case of education and training of NUMs/ANUMs, appropriate understanding of management obligations in relation to occupational health and safety, workers compensation and return to work by identifying gaps and making recommendations to address these, and</p><p><strong>(e)</strong> in the case of workplace bullying, identification of bullying prevention principles and practices, including education on early identification and intervention, appropriate workplace behaviour/Code of Conduct and appropriate investigation and feedback processes, and making recommendations to implement these.</p><p><strong>98.3</strong> As these matters are relevant to all Employees and Employers covered by this Agreement, an Industry OHS Working Group will be established consisting of no more than three representatives from each of the following:</p><p><strong>(a)</strong> the Unions;</p><p><strong>(b)</strong> VHIA;</p><p><strong>(c)</strong> DOH; and</p><p><strong>(d)</strong> other attendees as agreed by members of the working party.</p><p><strong>98.4</strong> In the case of the Unions and VHIA, a representative may include a member.</p><p><strong>98.5</strong> The Industry OHS Working Group will commence meeting within three (3) months of the commencement of the Agreement, and will meet bi-monthly or otherwise by agreement between its members.</p><p><strong>98.6</strong> The Industry OHS Working Group will determine any actions it will undertake, in addition to the above priorities.</p><p><strong>98.7</strong> The Industry OHS Working Group will operate with the oversight of the Central Implementation Committee and will produce annual reports to be provided to all parties on the progress, actions and recommendations resulting from the Group&#39;s work, with the first report to be delivered to the SDPPWG no more than 12 months after the first meeting.</p><p>Plain language terms: OHS committee, safety committee.</p>',27)])])}const m=n(i,[["render",s]]);export{h as __pageData,m as default};
